import React from 'react';
import { Card, CardContent, Typography, Box } from '@mui/material';

function StatCard({ title, value, icon, color = 'primary.main', textColor = 'white' }) {
  return (
    <Card 
      sx={{ 
        bgcolor: color,
        color: textColor,
        height: '100%',
        borderRadius: 3,
        boxShadow: '0px 4px 12px rgba(0, 0, 0, 0.05)'
      }}
    >
      <CardContent sx={{ p: 3 }}>
        <Typography variant="h6" fontWeight={500} mb={1}>
          {title}
        </Typography>
        <Typography variant="h4" fontWeight={600}>
          {value}
        </Typography>
        {icon && (
          <Box sx={{ 
            position: 'absolute', 
            top: 16, 
            right: 16, 
            opacity: 0.7 
          }}>
            {icon}
          </Box>
        )}
      </CardContent>
    </Card>
  );
}

export default StatCard;
